/*
 * GROUP 8 - interruptGtmAtom: ISR / interrupt behavior
 */
void test_TC_G8_001_isr_multiple_calls_accumulate(void)
{
    /* Act */
    for (int i = 0; i < 5; ++i)
    {
        interruptGtmAtom();
    }

